/* ================= DSCE_XTEST: the cross-game arena collision engine =================
 * SM64's ORIGINAL surface algorithms (surface_load read_surface_data + surface_collision
 * find_floor/find_ceil/find_wall_collisions, ported verbatim incl. s16 position
 * truncation, the 78-unit buffers, first-hit-breaks and the vertex1-height sort) running
 * over the generated arena tables -- the SAME triangles the sm64-xtest oracle ROM walks.
 * The find_* shims below route here under DSCE_XTEST, so cross-game runs compare the two
 * games on identical geometry with identical collision semantics. */
#if DSCE_XTEST
#include "../../dsce_xtest_arena.h"

static struct Surface sXtSurf[DSCE_XTEST_NUM_TRIS];
static struct Surface* sXtFloors[DSCE_XTEST_NUM_TRIS];
static struct Surface* sXtCeils[DSCE_XTEST_NUM_TRIS];
static struct Surface* sXtWalls[DSCE_XTEST_NUM_TRIS];
static s32 sXtNumFloors, sXtNumCeils, sXtNumWalls;
static s32 sXtInit = 0;

static void xt_insert_sorted(struct Surface** arr, s32* n, struct Surface* surf, s32 sortDir) {
    /* surface_load add_surface_to_cell: priority = vertex1[1] * sortDir, descending;
     * equal priorities keep insertion order (the new node goes after its equals). */
    s32 pri = surf->vertex1[1] * sortDir;
    s32 i = 0;
    s32 j;

    while ((i < *n) && (arr[i]->vertex1[1] * sortDir >= pri)) {
        i++;
    }
    for (j = *n; j > i; j--) {
        arr[j] = arr[j - 1];
    }
    arr[i] = surf;
    (*n)++;
}

static void xt_init(void) {
    s32 t;

    if (sXtInit) {
        return;
    }
    sXtInit = 1;
    for (t = 0; t < DSCE_XTEST_NUM_TRIS; t++) {
        struct Surface* surface = &sXtSurf[t];
        s32 x1 = sDsceXtestVerts[sDsceXtestTris[t][0]][0];
        s32 y1 = sDsceXtestVerts[sDsceXtestTris[t][0]][1];
        s32 z1 = sDsceXtestVerts[sDsceXtestTris[t][0]][2];
        s32 x2 = sDsceXtestVerts[sDsceXtestTris[t][1]][0];
        s32 y2 = sDsceXtestVerts[sDsceXtestTris[t][1]][1];
        s32 z2 = sDsceXtestVerts[sDsceXtestTris[t][1]][2];
        s32 x3 = sDsceXtestVerts[sDsceXtestTris[t][2]][0];
        s32 y3 = sDsceXtestVerts[sDsceXtestTris[t][2]][1];
        s32 z3 = sDsceXtestVerts[sDsceXtestTris[t][2]][2];
        f32 nx = (y2 - y1) * (z3 - z2) - (z2 - z1) * (y3 - y2);
        f32 ny = (z2 - z1) * (x3 - x2) - (x2 - x1) * (z3 - z2);
        f32 nz = (x2 - x1) * (y3 - y2) - (y2 - y1) * (x3 - x2);
        f32 mag = sqrtf(nx * nx + ny * ny + nz * nz);
        s32 minY = y1;
        s32 maxY = y1;

        if (y2 < minY) { minY = y2; }
        if (y3 < minY) { minY = y3; }
        if (y2 > maxY) { maxY = y2; }
        if (y3 > maxY) { maxY = y3; }
        if (mag < 0.0001f) {
            continue;
        }
        mag = (f32)(1.0 / mag);
        nx *= mag;
        ny *= mag;
        nz *= mag;
        surface->vertex1[0] = x1; surface->vertex1[1] = y1; surface->vertex1[2] = z1;
        surface->vertex2[0] = x2; surface->vertex2[1] = y2; surface->vertex2[2] = z2;
        surface->vertex3[0] = x3; surface->vertex3[1] = y3; surface->vertex3[2] = z3;
        surface->normal.x = nx;
        surface->normal.y = ny;
        surface->normal.z = nz;
        surface->originOffset = -(nx * x1 + ny * y1 + nz * z1);
        surface->lowerY = minY - 5;
        surface->upperY = maxY + 5;
        surface->type = sDsceXtestTris[t][3] ? SURFACE_BURNING : SURFACE_DEFAULT;
        surface->flags = 0;
        surface->room = 0;
        if (ny > 0.01f) {
            xt_insert_sorted(sXtFloors, &sXtNumFloors, surface, 1);
        } else if (ny < -0.01f) {
            xt_insert_sorted(sXtCeils, &sXtNumCeils, surface, -1);
        } else {
            if (surface->normal.x < -0.707f || surface->normal.x > 0.707f) {
                surface->flags |= SURFACE_FLAG_X_PROJECTION;
            }
            sXtWalls[sXtNumWalls++] = surface;
        }
    }
}

#define XT_LEVEL_BOUNDARY_MAX 0x2000
#define XT_FLOOR_LOWER_LIMIT -11000.0f
#define XT_CELL_HEIGHT_LIMIT 20000.0f

static struct Surface* xt_find_floor_from_list(s32 x, s32 y, s32 z, f32* pheight) {
    struct Surface* floor = NULL;
    s32 i;

    for (i = 0; i < sXtNumFloors; i++) {
        struct Surface* surf = sXtFloors[i];
        s32 x1 = surf->vertex1[0];
        s32 z1 = surf->vertex1[2];
        s32 x2 = surf->vertex2[0];
        s32 z2 = surf->vertex2[2];
        s32 x3, z3;
        f32 nx, ny, nz, oo, height;

        if ((z1 - z) * (x2 - x1) - (x1 - x) * (z2 - z1) < 0) {
            continue;
        }
        x3 = surf->vertex3[0];
        z3 = surf->vertex3[2];
        if ((z2 - z) * (x3 - x2) - (x2 - x) * (z3 - z2) < 0) {
            continue;
        }
        if ((z3 - z) * (x1 - x3) - (x3 - x) * (z1 - z3) < 0) {
            continue;
        }
        nx = surf->normal.x;
        ny = surf->normal.y;
        nz = surf->normal.z;
        oo = surf->originOffset;
        if (ny == 0.0f) {
            continue;
        }
        height = -(x * nx + nz * z + oo) / ny;
        if (y - (height + -78.0f) < 0.0f) {
            continue;
        }
        *pheight = height;
        floor = surf;
        break;
    }
    return floor;
}

static struct Surface* xt_find_ceil_from_list(s32 x, s32 y, s32 z, f32* pheight) {
    struct Surface* ceil = NULL;
    s32 i;

    for (i = 0; i < sXtNumCeils; i++) {
        struct Surface* surf = sXtCeils[i];
        s32 x1 = surf->vertex1[0];
        s32 z1 = surf->vertex1[2];
        s32 x2 = surf->vertex2[0];
        s32 z2 = surf->vertex2[2];
        s32 x3, z3;
        f32 nx, ny, nz, oo, height;

        /* ceilings use the REVERSED winding tests (original find_ceil_from_list) */
        if ((z1 - z) * (x2 - x1) - (x1 - x) * (z2 - z1) > 0) {
            continue;
        }
        x3 = surf->vertex3[0];
        z3 = surf->vertex3[2];
        if ((z2 - z) * (x3 - x2) - (x2 - x) * (z3 - z2) > 0) {
            continue;
        }
        if ((z3 - z) * (x1 - x3) - (x3 - x) * (z1 - z3) > 0) {
            continue;
        }
        nx = surf->normal.x;
        ny = surf->normal.y;
        nz = surf->normal.z;
        oo = surf->originOffset;
        if (ny == 0.0f) {
            continue;
        }
        height = -(x * nx + nz * z + oo) / ny;
        if (y - (height - -78.0f) > 0.0f) {
            continue;
        }
        *pheight = height;
        ceil = surf;
        break;
    }
    return ceil;
}

static s32 xt_find_wall_collisions(struct WallCollisionData* data) {
    struct WallCollisionData* col = data;
    f32 offset;
    f32 radius = col->radius;
    f32 x = col->x;
    f32 y = col->y + col->offsetY;
    f32 z = col->z;
    s32 numCols = 0;
    s32 i;

    if (radius > 200.0f) {
        radius = 200.0f;
    }
    col->numWalls = 0;
    for (i = 0; i < sXtNumWalls; i++) {
        struct Surface* surf = sXtWalls[i];
        f32 px = x, pz = z;
        f32 w1, w2, w3, y1, y2, y3;

        if (y < surf->lowerY || y > surf->upperY) {
            continue;
        }
        offset = surf->normal.x * x + surf->normal.y * y + surf->normal.z * z + surf->originOffset;
        if (offset < -radius || offset > radius) {
            continue;
        }
        if (surf->flags & SURFACE_FLAG_X_PROJECTION) {
            w1 = -surf->vertex1[2]; w2 = -surf->vertex2[2]; w3 = -surf->vertex3[2];
            y1 = surf->vertex1[1];  y2 = surf->vertex2[1];  y3 = surf->vertex3[1];
            if (surf->normal.x > 0.0f) {
                if ((y1 - y) * (w2 - w1) - (w1 - -pz) * (y2 - y1) > 0.0f) { continue; }
                if ((y2 - y) * (w3 - w2) - (w2 - -pz) * (y3 - y2) > 0.0f) { continue; }
                if ((y3 - y) * (w1 - w3) - (w3 - -pz) * (y1 - y3) > 0.0f) { continue; }
            } else {
                if ((y1 - y) * (w2 - w1) - (w1 - -pz) * (y2 - y1) < 0.0f) { continue; }
                if ((y2 - y) * (w3 - w2) - (w2 - -pz) * (y3 - y2) < 0.0f) { continue; }
                if ((y3 - y) * (w1 - w3) - (w3 - -pz) * (y1 - y3) < 0.0f) { continue; }
            }
        } else {
            w1 = surf->vertex1[0]; w2 = surf->vertex2[0]; w3 = surf->vertex3[0];
            y1 = surf->vertex1[1]; y2 = surf->vertex2[1]; y3 = surf->vertex3[1];
            if (surf->normal.z > 0.0f) {
                if ((y1 - y) * (w2 - w1) - (w1 - px) * (y2 - y1) > 0.0f) { continue; }
                if ((y2 - y) * (w3 - w2) - (w2 - px) * (y3 - y2) > 0.0f) { continue; }
                if ((y3 - y) * (w1 - w3) - (w3 - px) * (y1 - y3) > 0.0f) { continue; }
            } else {
                if ((y1 - y) * (w2 - w1) - (w1 - px) * (y2 - y1) < 0.0f) { continue; }
                if ((y2 - y) * (w3 - w2) - (w2 - px) * (y3 - y2) < 0.0f) { continue; }
                if ((y3 - y) * (w1 - w3) - (w3 - px) * (y1 - y3) < 0.0f) { continue; }
            }
        }
        /* the original pushes the queried position out along the wall's dominant axis */
        if (surf->flags & SURFACE_FLAG_X_PROJECTION) {
            x += surf->normal.x * (radius - offset);
        } else {
            z += surf->normal.z * (radius - offset);
        }
        if (col->numWalls < 4) {
            col->walls[col->numWalls++] = surf;
        }
        numCols++;
    }
    col->x = x;
    col->z = z;
    return numCols;
}
/* seed MarioState with the EXACT arena spawn constants (the hook's float roundtrip
 * through MM units would land ~1e-4 off; both games must start bit-identically) */
void Dsce_XtestSeedMario(void) {
    gMarioState->pos[0] = DSCE_XTEST_SPAWN_X;
    gMarioState->pos[1] = DSCE_XTEST_SPAWN_Y;
    gMarioState->pos[2] = DSCE_XTEST_SPAWN_Z;
    gMarioState->faceAngle[1] = DSCE_XTEST_SPAWN_YAW;
}

#endif /* DSCE_XTEST */
/* =============== end DSCE_XTEST collision engine =============== */

/* ---- collision shim: SM64 find_* -> MM BgCheck adapters ---- */
/* (gWaterSurfacePseudoFloor comes from mario_step.c, which the kernel vendors.) */
static struct Surface sDsceFloorSurf;
static struct Surface sDsceWallSurf;

f32 find_floor(f32 x, f32 y, f32 z, struct Surface** pfloor) {
    float h, nx, ny, nz;
    int danger = 0;
#if DSCE_XTEST
    { /* the arena IS the world: SM64's own algorithm over the shared triangles */
        s16 tx = (s16)(s32)x;
        s16 ty = (s16)(s32)y;
        s16 tz = (s16)(s32)z;
        f32 height = XT_FLOOR_LOWER_LIMIT;

        xt_init();
        *pfloor = NULL;
        if (tx <= -XT_LEVEL_BOUNDARY_MAX || tx >= XT_LEVEL_BOUNDARY_MAX ||
            tz <= -XT_LEVEL_BOUNDARY_MAX || tz >= XT_LEVEL_BOUNDARY_MAX) {
            return height;
        }
        *pfloor = xt_find_floor_from_list(tx, ty, tz, &height);
        return height;
    }
#endif
    if (Dsce_AdapterFindFloor(x, y, z, &h, &nx, &ny, &nz, &danger)) {
        /* lava/spike floors become SURFACE_BURNING so the vendored lava-boost reaction fires */
        sDsceFloorSurf.type = danger ? SURFACE_BURNING : SURFACE_DEFAULT;
        sDsceFloorSurf.normal.x = nx;
        sDsceFloorSurf.normal.y = ny;
        sDsceFloorSurf.normal.z = nz;
        sDsceFloorSurf.originOffset = -(nx * x + ny * h + nz * z);
        *pfloor = &sDsceFloorSurf;
        return h;
    }
    *pfloor = NULL;
    return -11000.0f;
}

f32 find_floor_height(f32 x, f32 y, f32 z) {
    struct Surface* s;
    return find_floor(x, y, z, &s);
}

static struct Surface sDsceCeilSurf;

f32 find_ceil(f32 x, f32 y, f32 z, struct Surface** pceil) {
    float h;
#if DSCE_XTEST
    {
        s16 tx = (s16)(s32)x;
        s16 ty = (s16)(s32)y;
        s16 tz = (s16)(s32)z;
        f32 height = XT_CELL_HEIGHT_LIMIT;

        xt_init();
        *pceil = NULL;
        if (tx <= -XT_LEVEL_BOUNDARY_MAX || tx >= XT_LEVEL_BOUNDARY_MAX ||
            tz <= -XT_LEVEL_BOUNDARY_MAX || tz >= XT_LEVEL_BOUNDARY_MAX) {
            return height;
        }
        *pceil = xt_find_ceil_from_list(tx, ty, tz, &height);
        return height;
    }
#endif
    if (Dsce_AdapterFindCeil(x, y, z, &h)) {
        sDsceCeilSurf.type = SURFACE_DEFAULT;
        sDsceCeilSurf.normal.x = 0.0f;
        sDsceCeilSurf.normal.y = -1.0f;
        sDsceCeilSurf.normal.z = 0.0f;
        sDsceCeilSurf.originOffset = h;
        *pceil = &sDsceCeilSurf;
        return h;
    }
    *pceil = NULL;
    return 20000.0f;
}

f32 find_water_level(f32 x, f32 z) {
    float surf;
#if DSCE_XTEST
    if (x >= DSCE_XTEST_WATER_X1 && x <= DSCE_XTEST_WATER_X2 &&
        z >= DSCE_XTEST_WATER_Z1 && z <= DSCE_XTEST_WATER_Z2) {
        return DSCE_XTEST_WATER_Y;
    }
    return -11000.0f;
#endif
    if (Dsce_AdapterFindWater(x, z, &surf)) {
        return surf;
    }
    return -11000.0f;
}

f32 find_poison_gas_level(f32 x, f32 z) {
    return -11000.0f;
}

s32 find_wall_collisions(struct WallCollisionData* colData) {
    float dx, dz, nx, ny, nz;
    float prevY;
    int danger;
#if DSCE_XTEST
    xt_init();
    return xt_find_wall_collisions(colData);
#endif
    colData->numWalls = 0;
    /* Every SM64 quarter-step queries a proposed local endpoint while gMarioState->pos
     * remains the last accepted endpoint.  Preserve that sweep for MM's wall solver;
     * passing next==prev disables its crossing test and leaves only shallow overlap
     * correction after Mario is already through the plane. */
    prevY = gMarioState->pos[1] + colData->offsetY;
    if (Dsce_AdapterFindWalls(colData->x, colData->y + colData->offsetY, colData->z,
                              gMarioState->pos[0], prevY, gMarioState->pos[2], colData->radius,
                              &dx, &dz, &nx, &ny, &nz, &danger)) {
        /* The adapter returns the ABSOLUTE pushed-out position (PC contract), not a delta.
         * (+= here doubled the position -> every walking quarter-step queried floor at 2x pos,
         * found void, and Mario could never move. Cost a long telemetry ladder to find.) */
        colData->x = dx;
        colData->z = dz;
        sDsceWallSurf.type = SURFACE_DEFAULT;
        sDsceWallSurf.normal.x = nx;
        sDsceWallSurf.normal.y = ny;
        sDsceWallSurf.normal.z = nz;
        colData->walls[0] = &sDsceWallSurf;
        colData->numWalls = 1;
    }
    return colData->numWalls;
}

s32 f32_find_wall_collision(f32* xPtr, f32* yPtr, f32* zPtr, f32 offsetY, f32 radius) {
    struct WallCollisionData col;
    col.x = *xPtr;
    col.y = *yPtr;
    col.z = *zPtr;
    col.offsetY = offsetY;
    col.radius = radius;
    find_wall_collisions(&col);
    *xPtr = col.x;
    *zPtr = col.z;
    return col.numWalls;
}

