/* ---- animation plumbing: REAL data (Phase 2). gDsceMarioAnimTable is generated at build
 * time from the user's SM64 ROM extraction (gen_mario_anims.py). set_mario_animation reads
 * list->bufTarget BEFORE calling us, so we must copy INTO the fixed buffer, never swap the
 * pointer. Our Animation structs carry absolute pointers -> always return FALSE (no rebase).
 * Missing ids keep the fake anim and are counted (the suite asserts the count stays 0). */
extern const struct Animation* const gDsceMarioAnimTable[];
extern const int gDsceMarioAnimTableLen;
u32 gDsceAnimFallbacks = 0;

s32 load_patchable_table(struct DmaHandlerList* list, s32 index) {
    struct Animation* buf = (struct Animation*) list->bufTarget; /* bufTarget is void* */
    const struct Animation* a = NULL;
    if ((index >= 0) && (index < gDsceMarioAnimTableLen)) {
        a = gDsceMarioAnimTable[index];
    }
    if (a != NULL) {
        *buf = *a;
    } else {
        gDsceAnimFallbacks++;
        buf->flags = 0;
        buf->animYTransDivisor = 1;
        buf->startFrame = 0;
        buf->loopStart = 0;
        buf->loopEnd = 2;
        buf->unusedBoneCount = 0;
        buf->values = sDsceFakeAnimValues;
        buf->index = sDsceFakeAnimIndex;
        buf->length = 0;
    }
    return FALSE;
}
